{
  "title": "उन्नत खोज सुविधाएँ",
  "group": "क्वेरी क्षमताएँ",
  "options": [
    {
      "text": "ElastiCache",
      "hint": "मुख्य रूप से एक इन-मेमोरी कैश है; नए Valkey वर्ज़न में सर्च फीचर्स शामिल हैं।"
    },
    {
      "text": "OpenSearch"
    },
    {
      "text": "Neptune",
      "hint": "एडवांस्ड क्वेरी क्षमताओं वाला ग्राफ डेटाबेस"
    },
    {
      "text": "Redshift",
      "hint": "जटिल एनालिटिकल क्वेरीज़"
    },
    {
      "text": "DocumentDB",
      "hint": "MongoDB-कम्पैटिबल क्वेरीज़"
    }
  ],
  "questionProse": [
    "इनमें से कौन सी AWS सर्विस फुल-टेक्स्ट सर्च और सर्च एनालिटिक्स के लिए खासतौर पर बनी है?"
  ],
  "explanationProse": [
    "OpenSearch AWS की मैनेज्ड सर्विस है जो खासतौर पर सर्च, लॉग एनालिटिक्स और फुल-टेक्स्ट सर्च वर्कलोड्स के लिए बनी है।\n\nबाकी विकल्प भी उपयोगी हैं, लेकिन इस लिस्ट में वे 'प्यरपस-बिल्ट' सर्च इंजन नहीं हैं:\n- ElastiCache: मुख्य रूप से एक इन-मेमोरी कैश है। हालाँकि, नए ElastiCache for Valkey में इंडेक्स्ड डेटा के लिए सर्च कमांड्स आते हैं, इसलिए इसे पूरी तरह से 'बिना सर्च वाली' सर्विस कहना अब सटीक नहीं है।\n- Neptune: यह एक ग्राफ डेटाबेस है। फुल-टेक्स्ट सर्च के लिए इसे अक्सर OpenSearch के साथ जोड़ा जाता है।\n- Redshift: यह SQL एनालिटिक्स के लिए बना डेटा वेयरहाउस है।\n- DocumentDB: यह एक डॉक्यूमेंट डेटाबेस है, जिसके सपोर्टेड वर्ज़न्स में MongoDB-जैसी टेक्स्ट सर्च की सुविधा मिलती है।"
  ]
}
